import{_ as e,c as a,o as s,a as i}from"./app.1cfac776.js";const g=JSON.parse('{"title":"Grupos","description":"","frontmatter":{},"headers":[],"relativePath":"ense\xF1anza/grupos.md"}'),r={name:"ense\xF1anza/grupos.md"},o=i('<h1 id="grupos" tabindex="-1">Grupos <a class="header-anchor" href="#grupos" aria-hidden="true">#</a></h1><p>De nuevo se trata de informaci\xF3n repetida en SIGAD pero la facilidad de uso hacen que se usen mucho m\xE1s las p\xE1ginas de IesApp que las de SIGAD.</p><p>Las p\xE1ginas disponibles son:</p><ul><li>Lista de alumnos</li><li>Orla de fotos</li><li>Horario de los grupos</li><li>Lista de claves para acceso a Aeducar</li><li>Actillas de evaluaci\xF3n</li></ul><p>Cabe destacar esto \xFAltimo. Las <strong>actillas de evaluaci\xF3n</strong> se registran en IesApp donde se recogen las inforaciones generales del grupo y particulares de cada alumno. En el caso de evaluaciones finales son la base para preparar la admisi\xF3n y matr\xEDcula para el curso siguiente.</p><p>Existe la posibilidad de gestionar las actillas de forma digital, haciendo que los profesores firmen en la plataforma, pero se tom\xF3 la decisi\xF3n de impirimir y firmar por ser reuniones de importancia, incluso legal.</p>',6),n=[o];function l(t,p,d,c,u,_){return s(),a("div",null,n)}const f=e(r,[["render",l]]);export{g as __pageData,f as default};
